import{_ as a}from"./plugin-vue_export-helper.21dcd24c.js";import{f as p}from"./app.788f2b88.js";const e={},r=p('<h1 id="\u9762\u5411\u5BF9\u8C61" tabindex="-1"><a class="header-anchor" href="#\u9762\u5411\u5BF9\u8C61" aria-hidden="true">#</a> \u9762\u5411\u5BF9\u8C61</h1><p>\u5728\u7B2C\u4E00\u4E2A\u6A21\u5757\u4E2D\uFF0C\u6211\u4EEC\u53C8\u9996\u5148\u4F1A\u8BB2\u5230\u9762\u5411\u5BF9\u8C61\u76F8\u5173\u7684\u7406\u8BBA\u77E5\u8BC6\u3002\u63D0\u5230\u9762\u5411\u5BF9\u8C61\uFF0C\u6211\u76F8\u4FE1\u5F88\u591A\u4EBA\u90FD\u4E0D\u964C\u751F\uFF0C\u968F\u53E3\u90FD\u53EF\u4EE5\u8BF4\u51FA\u9762\u5411\u5BF9\u8C61\u7684\u56DB\u5927\u7279\u6027\uFF1A\u5C01\u88C5\u3001\u62BD\u8C61\u3001\u7EE7\u627F\u3001\u591A\u6001\u3002\u5B9E\u9645\u4E0A\uFF0C\u9762\u5411\u5BF9\u8C61\u8FD9\u4E2A\u6982\u5FF5\u5305\u542B\u7684\u5185\u5BB9\u8FD8\u4E0D\u6B62\u8FD9\u4E9B\u3002\u6240\u4EE5\uFF0C\u4ECA\u5929\u6211\u6253\u7B97\u82B1\u4E00\u8282\u8BFE\u7684\u65F6\u95F4\uFF0C\u5148\u5927\u6982\u8DDF\u4F60\u804A\u4E00\u4E0B\uFF0C\u5F53\u6211\u4EEC\u8C08\u8BBA\u9762\u5411\u5BF9\u8C61\u7684\u65F6\u5019\uFF0C\u7ECF\u5E38\u4F1A\u8C08\u5230\u7684\u4E00\u4E9B\u6982\u5FF5\u548C\u77E5\u8BC6\u70B9\uFF0C\u4E3A\u5B66\u4E60\u540E\u9762\u7684\u51E0\u8282\u66F4\u52A0\u7EC6\u5316\u7684\u5185\u5BB9\u505A\u4E00\u4E2A\u94FA\u57AB\u3002</p><p>\u7279\u522B\u8BF4\u660E\u4E00\u4E0B\uFF0C\u5BF9\u4E8E\u4ECA\u5929\u8BB2\u5230\u7684\u6982\u5FF5\u548C\u77E5\u8BC6\u70B9\uFF0C\u5927\u90E8\u5206\u6211\u90FD\u662F\u70B9\u5230\u4E3A\u6B62\uFF0C\u5E76\u6CA1\u6709\u5C55\u5F00\u8BE6\u7EC6\u8BB2\u89E3\u3002\u5982\u679C\u4F60\u770B\u4E86\u4E4B\u540E\uFF0C\u5BF9\u67D0\u4E2A\u6982\u5FF5\u548C\u77E5\u8BC6\u70B9\u8FD8\u4E0D\u662F\u5F88\u6E05\u695A\uFF0C\u90A3\u4E5F\u6CA1\u6709\u5173\u7CFB\u3002\u5728\u540E\u9762\u7684\u51E0\u8282\u8BFE\u4E2D\uFF0C\u6211\u4F1A\u82B1\u66F4\u591A\u7684\u7BC7\u5E45\uFF0C\u5BF9\u4ECA\u5929\u8BB2\u5230\u7684\u6BCF\u4E2A\u6982\u5FF5\u548C\u77E5\u8BC6\u70B9\uFF0C\u7ED3\u5408\u5177\u4F53\u7684\u4F8B\u5B50\uFF0C\u4E00\u4E00\u505A\u8BE6\u7EC6\u7684\u8BB2\u89E3\u3002</p><h2 id="\u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u548C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00" tabindex="-1"><a class="header-anchor" href="#\u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u548C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00" aria-hidden="true">#</a> \u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u548C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\uFF1F</h2><p>\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u7684\u82F1\u6587\u7F29\u5199\u662F OOP\uFF0C\u5168\u79F0\u662F Object Oriented Programming\u3002\u5BF9\u5E94\u5730\uFF0C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u7684\u82F1\u6587\u7F29\u5199\u662F OOPL\uFF0C\u5168\u79F0\u662F Object Oriented Programming Language\u3002</p><p>\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u4E2D\u6709\u4E24\u4E2A\u975E\u5E38\u91CD\u8981\u3001\u975E\u5E38\u57FA\u7840\u7684\u6982\u5FF5\uFF0C\u90A3\u5C31\u662F\u7C7B\uFF08class\uFF09\u548C\u5BF9\u8C61\uFF08object\uFF09\u3002\u8FD9\u4E24\u4E2A\u6982\u5FF5\u6700\u65E9\u51FA\u73B0\u5728 1960 \u5E74\uFF0C\u5728 Simula \u8FD9\u79CD\u7F16\u7A0B\u8BED\u8A00\u4E2D\u7B2C\u4E00\u6B21\u4F7F\u7528\u3002\u800C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8FD9\u4E2A\u6982\u5FF5\u7B2C\u4E00\u6B21\u88AB\u4F7F\u7528\u662F\u5728 Smalltalk \u8FD9\u79CD\u7F16\u7A0B\u8BED\u8A00\u4E2D\u3002Smalltalk \u88AB\u8BA4\u4E3A\u662F\u7B2C\u4E00\u4E2A\u771F\u6B63\u610F\u4E49\u4E0A\u7684\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u3002</p><p>1980 \u5E74\u5DE6\u53F3\uFF0CC++ \u7684\u51FA\u73B0\uFF0C\u5E26\u52A8\u4E86\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u7684\u6D41\u884C\uFF0C\u4E5F\u4F7F\u5F97\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u88AB\u8D8A\u6765\u8D8A\u591A\u7684\u4EBA\u8BA4\u53EF\u3002\u76F4\u5230\u4ECA\u5929\uFF0C\u5982\u679C\u4E0D\u6309\u7167\u4E25\u683C\u7684\u5B9A\u4E49\u6765\u8BF4\uFF0C\u5927\u90E8\u5206\u7F16\u7A0B\u8BED\u8A00\u90FD\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\uFF0C\u6BD4\u5982 Java\u3001C++\u3001Go\u3001Python\u3001C#\u3001Ruby\u3001JavaScript\u3001Objective-C\u3001Scala\u3001PHP\u3001Perl \u7B49\u7B49\u3002\u9664\u6B64\u4E4B\u5916\uFF0C\u5927\u90E8\u5206\u7A0B\u5E8F\u5458\u5728\u5F00\u53D1\u9879\u76EE\u7684\u65F6\u5019\uFF0C\u90FD\u662F\u57FA\u4E8E\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u8FDB\u884C\u7684\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u3002</p><p>\u4EE5\u4E0A\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u7684\u5927\u6982\u53D1\u5C55\u5386\u53F2\u3002\u5728\u521A\u521A\u7684\u63CF\u8FF0\u4E2D\uFF0C\u6211\u7740\u91CD\u63D0\u5230\u4E86\u4E24\u4E2A\u6982\u5FF5\uFF0C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u548C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u3002\u90A3\u7A76\u7ADF\u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\uFF1F\u4EC0\u4E48\u8BED\u8A00\u624D\u7B97\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u5462\uFF1F\u5982\u679C\u975E\u5F97\u7ED9\u51FA\u4E00\u4E2A\u5B9A\u4E49\u7684\u8BDD\uFF0C\u6211\u89C9\u5F97\u53EF\u4EE5\u7528\u4E0B\u9762\u4E24\u53E5\u8BDD\u6765\u6982\u62EC\u3002</p><p>\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u662F\u4E00\u79CD\u7F16\u7A0B\u8303\u5F0F\u6216\u7F16\u7A0B\u98CE\u683C\u3002\u5B83\u4EE5\u7C7B\u6216\u5BF9\u8C61\u4F5C\u4E3A\u7EC4\u7EC7\u4EE3\u7801\u7684\u57FA\u672C\u5355\u5143\uFF0C\u5E76\u5C06\u5C01\u88C5\u3001\u62BD\u8C61\u3001\u7EE7\u627F\u3001\u591A\u6001\u56DB\u4E2A\u7279\u6027\uFF0C\u4F5C\u4E3A\u4EE3\u7801\u8BBE\u8BA1\u548C\u5B9E\u73B0\u7684\u57FA\u77F3 \u3002</p><p>\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u662F\u652F\u6301\u7C7B\u6216\u5BF9\u8C61\u7684\u8BED\u6CD5\u673A\u5236\uFF0C\u5E76\u6709\u73B0\u6210\u7684\u8BED\u6CD5\u673A\u5236\uFF0C\u80FD\u65B9\u4FBF\u5730\u5B9E\u73B0\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u56DB\u5927\u7279\u6027\uFF08\u5C01\u88C5\u3001\u62BD\u8C61\u3001\u7EE7\u627F\u3001\u591A\u6001\uFF09\u7684\u7F16\u7A0B\u8BED\u8A00\u3002</p><p>\u4E00\u822C\u6765\u8BB2\uFF0C \u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u90FD\u662F\u901A\u8FC7\u4F7F\u7528\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u6765\u8FDB\u884C\u7684\uFF0C\u4F46\u662F\uFF0C\u4E0D\u7528\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\uFF0C\u6211\u4EEC\u7167\u6837\u53EF\u4EE5\u8FDB\u884C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u3002\u53CD\u8FC7\u6765\u8BB2\uFF0C\u5373\u4FBF\u6211\u4EEC\u4F7F\u7528\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\uFF0C\u5199\u51FA\u6765\u7684\u4EE3\u7801\u4E5F\u4E0D\u4E00\u5B9A\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u98CE\u683C\u7684\uFF0C\u4E5F\u6709\u53EF\u80FD\u662F\u9762\u5411\u8FC7\u7A0B\u7F16\u7A0B\u98CE\u683C\u7684\u3002\u8FD9\u91CC\u542C\u8D77\u6765\u662F\u4E0D\u662F\u6709\u70B9\u7ED5\uFF1F\u4E0D\u8FC7\u6CA1\u5173\u7CFB\uFF0C\u6211\u4EEC\u5728\u540E\u9762\u7684\u7B2C 7 \u8282\u8BFE\u4E2D\uFF0C\u4F1A\u8BE6\u7EC6\u8BB2\u89E3\u8FD9\u4E2A\u95EE\u9898\u3002</p><p>\u9664\u6B64\u4E4B\u5916\uFF0C\u4ECE\u5B9A\u4E49\u4E2D\uFF0C\u6211\u4EEC\u8FD8\u53EF\u4EE5\u53D1\u73B0\uFF0C\u7406\u89E3\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u53CA\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u4E24\u4E2A\u6982\u5FF5\uFF0C\u5176\u4E2D\u6700\u5173\u952E\u7684\u4E00\u70B9\u5C31\u662F\u7406\u89E3\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u7684\u56DB\u5927\u7279\u6027\u3002\u8FD9\u56DB\u5927\u7279\u6027\u5206\u522B\u662F\uFF1A\u5C01\u88C5\u3001\u62BD\u8C61\u3001\u7EE7\u627F\u3001\u591A\u6001\u3002\u4E0D\u8FC7\uFF0C\u5173\u4E8E\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u7684\u7279\u6027\uFF0C\u4E5F\u6709\u53E6\u5916\u4E00\u79CD\u8BF4\u6CD5\uFF0C\u90A3\u5C31\u662F\u53EA\u5305\u542B\u4E09\u5927\u7279\u6027\uFF1A\u5C01\u88C5\u3001\u7EE7\u627F\u3001\u591A\u6001\uFF0C\u4E0D\u5305\u542B\u62BD\u8C61\u3002\u4E3A\u4EC0\u4E48\u4F1A\u6709\u8FD9\u79CD\u5206\u6B67\u5462\uFF1F\u62BD\u8C61\u4E3A\u4EC0\u4E48\u53EF\u4EE5\u6392\u9664\u5728\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u7279\u6027\u4E4B\u5916\u5462\uFF1F\u5173\u4E8E\u8FD9\u4E2A\u95EE\u9898\uFF0C\u5728\u4E0B\u4E00\u8282\u8BFE\u8BE6\u7EC6\u8BB2\u89E3\u8FD9\u56DB\u5927\u7279\u6027\u7684\u65F6\u5019\uFF0C\u6211\u8FD8\u4F1A\u518D\u62FF\u51FA\u6765\u8BF4\u4E00\u4E0B\u3002\u4E0D\u8FC7\uFF0C\u8BDD\u8BF4\u56DE\u6765\uFF0C\u5B9E\u9645\u4E0A\uFF0C\u6211\u4EEC\u6CA1\u5FC5\u8981\u7EA0\u7ED3\u5230\u5E95\u662F\u56DB\u5927\u7279\u6027\u8FD8\u662F\u4E09\u5927\u7279\u6027\uFF0C\u5173\u952E\u8FD8\u662F\u7406\u89E3\u6BCF\u79CD\u7279\u6027\u8BB2\u7684\u662F\u4EC0\u4E48\u5185\u5BB9\u3001\u5B58\u5728\u7684\u610F\u4E49\u4EE5\u53CA\u80FD\u89E3\u51B3\u4EC0\u4E48\u95EE\u9898\u3002</p><p>\u800C\u4E14\uFF0C\u5728\u6280\u672F\u5708\u91CC\uFF0C\u5C01\u88C5\u3001\u62BD\u8C61\u3001\u7EE7\u627F\u3001\u591A\u6001\u4E5F\u5E76\u4E0D\u662F\u56FA\u5B9A\u5730\u88AB\u53EB\u4F5C\u201C\u56DB\u5927\u7279\u6027\u201D\uFF08features\uFF09\uFF0C\u4E5F\u6709\u4EBA\u79F0\u5B83\u4EEC\u4E3A\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u7684\u56DB\u5927\u6982\u5FF5\uFF08concepts\uFF09\u3001\u56DB\u5927\u57FA\u77F3\uFF08cornerstones\uFF09\u3001\u56DB\u5927\u57FA\u7840\uFF08fundamentals\uFF09\u3001\u56DB\u5927\u652F\u67F1\uFF08pillars\uFF09\u7B49\u7B49\u3002\u4F60\u4E5F\u53D1\u73B0\u4E86\u5427\uFF0C\u53EB\u6CD5\u633A\u6DF7\u4E71\u7684\u3002\u4E0D\u8FC7\uFF0C\u53EB\u4EC0\u4E48\u5E76\u4E0D\u91CD\u8981\u3002\u6211\u4EEC\u53EA\u9700\u8981\u77E5\u9053\uFF0C\u8FD9\u662F\u524D\u4EBA\u8FDB\u884C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8FC7\u7A0B\u4E2D\u603B\u7ED3\u51FA\u6765\u7684\u3001\u80FD\u8BA9\u6211\u4EEC\u66F4\u5BB9\u6613\u5730\u5B9E\u73B0\u5404\u79CD\u8BBE\u8BA1\u601D\u8DEF\u7684\u51E0\u4E2A\u7F16\u7A0B\u5957\u8DEF\uFF0C\u8FD9\u5C31\u591F\u4E86\u3002\u5728\u4E4B\u540E\u7684\u8BFE\u7A0B\u8BB2\u89E3\u4E2D\uFF0C\u6211\u7EDF\u4E00\u628A\u5B83\u4EEC\u53EB\u4F5C\u201C\u56DB\u5927\u7279\u6027\u201D\u3002</p><h2 id="\u5982\u4F55\u5224\u5B9A\u67D0\u7F16\u7A0B\u8BED\u8A00\u662F\u5426\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00" tabindex="-1"><a class="header-anchor" href="#\u5982\u4F55\u5224\u5B9A\u67D0\u7F16\u7A0B\u8BED\u8A00\u662F\u5426\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00" aria-hidden="true">#</a> \u5982\u4F55\u5224\u5B9A\u67D0\u7F16\u7A0B\u8BED\u8A00\u662F\u5426\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\uFF1F</h2><p>\u5982\u679C\u4F60\u8DB3\u591F\u7EC6\u5FC3\uFF0C\u4F60\u53EF\u80FD\u5DF2\u7ECF\u7559\u610F\u5230\uFF0C\u5728\u6211\u521A\u521A\u7684\u8BB2\u89E3\u4E2D\uFF0C\u6211\u63D0\u5230\uFF0C\u201C\u5982\u679C\u4E0D\u6309\u7167\u4E25\u683C\u7684\u5B9A\u4E49\u6765\u8BF4\uFF0C\u5927\u90E8\u5206\u7F16\u7A0B\u8BED\u8A00\u90FD\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u201D\u3002\u4E3A\u4EC0\u4E48\u8981\u52A0\u4E0A\u201C\u5982\u679C\u4E0D\u6309\u7167\u4E25\u683C\u7684\u5B9A\u4E49\u201D\u8FD9\u4E2A\u524D\u63D0\u5462\uFF1F\u90A3\u662F\u56E0\u4E3A\uFF0C\u5982\u679C\u6309\u7167\u521A\u521A\u6211\u4EEC\u7ED9\u51FA\u7684\u4E25\u683C\u7684\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u7684\u5B9A\u4E49\uFF0C\u524D\u9762\u63D0\u5230\u7684\u6709\u4E9B\u7F16\u7A0B\u8BED\u8A00\uFF0C\u5E76\u4E0D\u662F\u4E25\u683C\u610F\u4E49\u4E0A\u7684\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\uFF0C\u6BD4\u5982 JavaScript\uFF0C\u5B83\u4E0D\u652F\u6301\u5C01\u88C5\u548C\u7EE7\u627F\u7279\u6027\uFF0C\u6309\u7167\u4E25\u683C\u7684\u5B9A\u4E49\uFF0C\u5B83\u4E0D\u7B97\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\uFF0C\u4F46\u5728\u67D0\u79CD\u610F\u4E49\u4E0A\uFF0C\u5B83\u53C8\u53EF\u4EE5\u7B97\u5F97\u4E0A\u662F\u4E00\u79CD\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u3002\u6211\u4E3A\u4EC0\u4E48\u8FD9\u4E48\u8BF4\u5462\uFF1F\u5230\u5E95\u8BE5\u5982\u4F55\u5224\u65AD\u4E00\u4E2A\u7F16\u7A0B\u8BED\u8A00\u662F\u5426\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u5462\uFF1F</p><p>\u8FD8\u8BB0\u5F97\u6211\u4EEC\u524D\u9762\u7ED9\u51FA\u7684\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u53CA\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u7684\u5B9A\u4E49\u5417\uFF1F\u5982\u679C\u5FD8\u8BB0\u4E86\uFF0C\u4F60\u53EF\u4EE5\u5148\u7FFB\u5230\u4E0A\u9762\u56DE\u987E\u4E00\u4E0B\u3002\u4E0D\u8FC7\uFF0C\u6211\u5FC5\u987B\u5766\u8BDA\u544A\u8BC9\u4F60\uFF0C\u90A3\u4E2A\u5B9A\u4E49\u662F\u6211\u81EA\u5DF1\u7ED9\u51FA\u7684\u3002\u5B9E\u9645\u4E0A\uFF0C\u5BF9\u4E8E\u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u3001\u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\uFF0C\u5E76\u6CA1\u6709\u4E00\u4E2A\u5B98\u65B9\u7684\u3001\u7EDF\u4E00\u7684\u5B9A\u4E49\u3002\u800C\u4E14\uFF0C\u4ECE 1960 \u5E74\uFF0C\u4E5F\u5C31\u662F 60 \u5E74\u524D\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BDE\u751F\u5F00\u59CB\uFF0C\u8FD9\u4E24\u4E2A\u6982\u5FF5\u5C31\u5728\u4E0D\u505C\u5730\u6F14\u5316\uFF0C\u6240\u4EE5\uFF0C\u4E5F\u65E0\u6CD5\u7ED9\u51FA\u4E00\u4E2A\u660E\u786E\u7684\u5B9A\u4E49\uFF0C\u4E5F\u6CA1\u6709\u5FC5\u8981\u7ED9\u51FA\u4E00\u4E2A\u660E\u786E\u5B9A\u4E49\u3002</p><p>\u5B9E\u9645\u4E0A\uFF0C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u4ECE\u5B57\u9762\u4E0A\uFF0C\u6309\u7167\u6700\u7B80\u5355\u3001\u6700\u539F\u59CB\u7684\u65B9\u5F0F\u6765\u7406\u89E3\uFF0C\u5C31\u662F\u5C06\u5BF9\u8C61\u6216\u7C7B\u4F5C\u4E3A\u4EE3\u7801\u7EC4\u7EC7\u7684\u57FA\u672C\u5355\u5143\uFF0C\u6765\u8FDB\u884C\u7F16\u7A0B\u7684\u4E00\u79CD\u7F16\u7A0B\u8303\u5F0F\u6216\u8005\u7F16\u7A0B\u98CE\u683C\uFF0C\u5E76\u4E0D\u4E00\u5B9A\u9700\u8981\u5C01\u88C5\u3001\u62BD\u8C61\u3001\u7EE7\u627F\u3001\u591A\u6001\u8FD9\u56DB\u5927\u7279\u6027\u7684\u652F\u6301\u3002\u4F46\u662F\uFF0C\u5728\u8FDB\u884C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u4EBA\u4EEC\u4E0D\u505C\u5730\u603B\u7ED3\u53D1\u73B0\uFF0C\u6709\u4E86\u8FD9\u56DB\u5927\u7279\u6027\uFF0C\u6211\u4EEC\u5C31\u80FD\u66F4\u5BB9\u6613\u5730\u5B9E\u73B0\u5404\u79CD\u9762\u5411\u5BF9\u8C61\u7684\u4EE3\u7801\u8BBE\u8BA1\u601D\u8DEF\u3002</p><p>\u6BD4\u5982\uFF0C\u6211\u4EEC\u5728\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u7ECF\u5E38\u4F1A\u9047\u5230 is-a \u8FD9\u79CD\u7C7B\u5173\u7CFB\uFF08\u6BD4\u5982\u72D7\u662F\u4E00\u79CD\u52A8\u7269\uFF09\uFF0C\u800C\u7EE7\u627F\u8FD9\u4E2A\u7279\u6027\u5C31\u80FD\u5F88\u597D\u5730\u652F\u6301\u8FD9\u79CD is-a \u7684\u4EE3\u7801\u8BBE\u8BA1\u601D\u8DEF\uFF0C\u5E76\u4E14\u89E3\u51B3\u4EE3\u7801\u590D\u7528\u7684\u95EE\u9898\uFF0C\u6240\u4EE5\uFF0C\u7EE7\u627F\u5C31\u6210\u4E86\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u7684\u56DB\u5927\u7279\u6027\u4E4B\u4E00\u3002\u4F46\u662F\u968F\u7740\u7F16\u7A0B\u8BED\u8A00\u7684\u4E0D\u65AD\u8FED\u4EE3\u3001\u6F14\u5316\uFF0C\u4EBA\u4EEC\u53D1\u73B0\u7EE7\u627F\u8FD9\u79CD\u7279\u6027\u5BB9\u6613\u9020\u6210\u5C42\u6B21\u4E0D\u6E05\u3001\u4EE3\u7801\u6DF7\u4E71\uFF0C\u6240\u4EE5\uFF0C\u5F88\u591A\u7F16\u7A0B\u8BED\u8A00\u5728\u8BBE\u8BA1\u7684\u65F6\u5019\u5C31\u5F00\u59CB\u6452\u5F03\u7EE7\u627F\u7279\u6027\uFF0C\u6BD4\u5982 Go \u8BED\u8A00\u3002\u4F46\u662F\uFF0C\u6211\u4EEC\u5E76\u4E0D\u80FD\u56E0\u4E3A\u5B83\u6452\u5F03\u4E86\u7EE7\u627F\u7279\u6027\uFF0C\u5C31\u4E00\u5200\u5207\u5730\u8BA4\u4E3A\u5B83\u4E0D\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u4E86\u3002</p><p>\u5B9E\u9645\u4E0A\uFF0C\u6211\u4E2A\u4EBA\u89C9\u5F97\uFF0C\u53EA\u8981\u67D0\u79CD\u7F16\u7A0B\u8BED\u8A00\u652F\u6301\u7C7B\u6216\u5BF9\u8C61\u7684\u8BED\u6CD5\u6982\u5FF5\uFF0C\u5E76\u4E14\u4EE5\u6B64\u4F5C\u4E3A\u7EC4\u7EC7\u4EE3\u7801\u7684\u57FA\u672C\u5355\u5143\uFF0C\u90A3\u5C31\u53EF\u4EE5\u88AB\u7C97\u7565\u5730\u8BA4\u4E3A\u5B83\u5C31\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u4E86\u3002\u81F3\u4E8E\u662F\u5426\u6709\u73B0\u6210\u7684\u8BED\u6CD5\u673A\u5236\uFF0C\u5B8C\u5168\u5730\u652F\u6301\u4E86\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u7684\u56DB\u5927\u7279\u6027\u3001\u662F\u5426\u5BF9\u56DB\u5927\u7279\u6027\u6709\u6240\u53D6\u820D\u548C\u4F18\u5316\uFF0C\u53EF\u4EE5\u4E0D\u4F5C\u4E3A\u5224\u5B9A\u7684\u6807\u51C6\u3002\u57FA\u4E8E\u6B64\uFF0C\u6211\u4EEC\u624D\u6709\u4E86\u524D\u9762\u7684\u8BF4\u6CD5\uFF0C<strong>\u6309\u7167\u4E25\u683C\u7684\u5B9A\u4E49\uFF0C\u5F88\u591A\u8BED\u8A00\u90FD\u4E0D\u80FD\u7B97\u5F97\u4E0A\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\uFF0C\u4F46\u6309\u7167\u4E0D\u4E25\u683C\u7684\u5B9A\u4E49\u6765\u8BB2\uFF0C\u73B0\u5728\u6D41\u884C\u7684\u5927\u90E8\u5206\u7F16\u7A0B\u8BED\u8A00\u90FD\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u3002</strong></p><p>\u6240\u4EE5\uFF0C\u591A\u8BF4\u4E00\u53E5\uFF0C\u5173\u4E8E\u8FD9\u4E2A\u95EE\u9898\uFF0C\u6211\u4EEC\u4E00\u5B9A\u4E0D\u8981\u8FC7\u4E8E\u5B66\u9662\u6D3E\uFF0C\u975E\u8981\u7ED9\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u3001\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u4E0B\u4E2A\u6B7B\u5B9A\u4E49\uFF0C\u975E\u5F97\u5BF9\u67D0\u79CD\u8BED\u8A00\u662F\u5426\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u4E89\u4E2A\u4E00\u6E05\u4E8C\u767D\uFF0C\u8FD9\u6837\u505A\u610F\u4E49\u4E0D\u5927\u3002</p><h2 id="\u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u5206\u6790\u548C\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1" tabindex="-1"><a class="header-anchor" href="#\u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u5206\u6790\u548C\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1" aria-hidden="true">#</a> \u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u5206\u6790\u548C\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\uFF1F</h2><p>\u524D\u9762\u6211\u4EEC\u8BB2\u4E86\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\uFF08OOP\uFF09\uFF0C\u5B9E\u9645\u4E0A\uFF0C\u8DDF\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u7ECF\u5E38\u653E\u5230\u4E00\u5757\u513F\u6765\u8BB2\u7684\u8FD8\u6709\u53E6\u5916\u4E24\u4E2A\u6982\u5FF5\uFF0C\u90A3\u5C31\u662F\u9762\u5411\u5BF9\u8C61\u5206\u6790\uFF08OOA\uFF09\u548C\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\uFF08OOD\uFF09\u3002\u9762\u5411\u5BF9\u8C61\u5206\u6790\u82F1\u6587\u7F29\u5199\u662F OOA\uFF0C\u5168\u79F0\u662F Object Oriented Analysis\uFF1B\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\u7684\u82F1\u6587\u7F29\u5199\u662F OOD\uFF0C\u5168\u79F0\u662F Object Oriented Design\u3002OOA\u3001OOD\u3001OOP \u4E09\u4E2A\u8FDE\u5728\u4E00\u8D77\u5C31\u662F\u9762\u5411\u5BF9\u8C61\u5206\u6790\u3001\u8BBE\u8BA1\u3001\u7F16\u7A0B\uFF08\u5B9E\u73B0\uFF09\uFF0C\u6B63\u597D\u662F\u9762\u5411\u5BF9\u8C61\u8F6F\u4EF6\u5F00\u53D1\u8981\u7ECF\u5386\u7684\u4E09\u4E2A\u9636\u6BB5\u3002</p><p>\u5173\u4E8E\u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\uFF0C\u6211\u4EEC\u524D\u9762\u5DF2\u7ECF\u8BB2\u8FC7\u4E86\u3002\u6211\u4EEC\u73B0\u5728\u518D\u6765\u8BB2\u4E00\u4E0B\uFF0C\u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u5206\u6790\u548C\u8BBE\u8BA1\u3002\u8FD9\u4E24\u4E2A\u6982\u5FF5\u76F8\u5BF9\u6765\u8BF4\u8981\u7B80\u5355\u4E00\u4E9B\u3002\u9762\u5411\u5BF9\u8C61\u5206\u6790\u4E0E\u8BBE\u8BA1\u4E2D\u7684\u201C\u5206\u6790\u201D\u548C\u201C\u8BBE\u8BA1\u201D\u8FD9\u4E24\u4E2A\u8BCD\uFF0C\u6211\u4EEC\u5B8C\u5168\u53EF\u4EE5\u4ECE\u5B57\u9762\u4E0A\u53BB\u7406\u89E3\uFF0C\u4E0D\u9700\u8981\u8FC7\u5EA6\u89E3\u8BFB\uFF0C\u7B80\u5355\u7C7B\u6BD4\u8F6F\u4EF6\u5F00\u53D1\u4E2D\u7684\u9700\u6C42\u5206\u6790\u3001\u7CFB\u7EDF\u8BBE\u8BA1\u5373\u53EF\u3002\u4E0D\u8FC7\uFF0C\u4F60\u53EF\u80FD\u4F1A\u8BF4\uFF0C\u90A3\u4E3A\u5565\u524D\u9762\u8FD8\u52A0\u4E86\u4E2A\u4FEE\u9970\u8BCD\u201C\u9762\u5411\u5BF9\u8C61\u201D\u5462\uFF1F\u6709\u4EC0\u4E48\u7279\u6B8A\u7684\u610F\u4E49\u5417\uFF1F</p><p>\u4E4B\u6240\u4EE5\u5728\u524D\u9762\u52A0\u201C\u9762\u5411\u5BF9\u8C61\u201D\u8FD9\u51E0\u4E2A\u5B57\uFF0C\u662F\u56E0\u4E3A\u6211\u4EEC\u662F\u56F4\u7ED5\u7740\u5BF9\u8C61\u6216\u7C7B\u6765\u505A\u9700\u6C42\u5206\u6790\u548C\u8BBE\u8BA1\u7684\u3002\u5206\u6790\u548C\u8BBE\u8BA1\u4E24\u4E2A\u9636\u6BB5\u6700\u7EC8\u7684\u4EA7\u51FA\u662F\u7C7B\u7684\u8BBE\u8BA1\uFF0C\u5305\u62EC\u7A0B\u5E8F\u88AB\u62C6\u89E3\u4E3A\u54EA\u4E9B\u7C7B\uFF0C\u6BCF\u4E2A\u7C7B\u6709\u54EA\u4E9B\u5C5E\u6027\u65B9\u6CD5\uFF0C\u7C7B\u4E0E\u7C7B\u4E4B\u95F4\u5982\u4F55\u4EA4\u4E92\u7B49\u7B49\u3002\u5B83\u4EEC\u6BD4\u5176\u4ED6\u7684\u5206\u6790\u548C\u8BBE\u8BA1\u66F4\u52A0\u5177\u4F53\u3001\u66F4\u52A0\u843D\u5730\u3001\u66F4\u52A0\u8D34\u8FD1\u7F16\u7801\uFF0C\u66F4\u80FD\u591F\u987A\u5229\u5730\u8FC7\u6E21\u5230\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u73AF\u8282\u3002\u8FD9\u4E5F\u662F\u9762\u5411\u5BF9\u8C61\u5206\u6790\u548C\u8BBE\u8BA1\uFF0C\u4E0E\u5176\u4ED6\u5206\u6790\u548C\u8BBE\u8BA1\u6700\u5927\u7684\u4E0D\u540C\u70B9\u3002</p><p>\u770B\u5230\u8FD9\u91CC\uFF0C\u4F60\u53EF\u80FD\u4F1A\u95EE\uFF0C\u90A3\u9762\u5411\u5BF9\u8C61\u5206\u6790\u3001\u8BBE\u8BA1\u3001\u7F16\u7A0B\u5230\u5E95\u90FD\u8D1F\u8D23\u505A\u54EA\u4E9B\u5DE5\u4F5C\u5462\uFF1F\u7B80\u5355\u70B9\u8BB2\uFF0C\u9762\u5411\u5BF9\u8C61\u5206\u6790\u5C31\u662F\u8981\u641E\u6E05\u695A\u505A\u4EC0\u4E48\uFF0C\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\u5C31\u662F\u8981\u641E\u6E05\u695A\u600E\u4E48\u505A\uFF0C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u5C31\u662F\u5C06\u5206\u6790\u548C\u8BBE\u8BA1\u7684\u7684\u7ED3\u679C\u7FFB\u8BD1\u6210\u4EE3\u7801\u7684\u8FC7\u7A0B\u3002\u4ECA\u5929\uFF0C\u6211\u4EEC\u53EA\u662F\u7B80\u5355\u4ECB\u7ECD\u4E00\u4E0B\u6982\u5FF5\uFF0C\u4E0D\u5C55\u5F00\u8BE6\u7EC6\u8BB2\u89E3\u3002\u5728\u540E\u9762\u7684\u9762\u5411\u5BF9\u8C61\u5B9E\u6218\u73AF\u8282\u4E2D\uFF0C\u6211\u4F1A\u7528\u4E24\u8282\u8BFE\u7684\u65F6\u95F4\uFF0C\u901A\u8FC7\u4E00\u4E2A\u5B9E\u9645\u4F8B\u5B50\uFF0C\u8BE6\u7EC6\u8BB2\u89E3\u5982\u4F55\u8FDB\u884C\u9762\u5411\u5BF9\u8C61\u5206\u6790\u3001\u8BBE\u8BA1\u548C\u7F16\u7A0B\u3002</p><h2 id="\u4EC0\u4E48\u662F-uml-\u6211\u4EEC\u662F\u5426\u9700\u8981-uml" tabindex="-1"><a class="header-anchor" href="#\u4EC0\u4E48\u662F-uml-\u6211\u4EEC\u662F\u5426\u9700\u8981-uml" aria-hidden="true">#</a> \u4EC0\u4E48\u662F UML\uFF1F\u6211\u4EEC\u662F\u5426\u9700\u8981 UML\uFF1F</h2><p>\u8BB2\u5230\u9762\u5411\u5BF9\u8C61\u5206\u6790\u3001\u8BBE\u8BA1\u3001\u7F16\u7A0B\uFF0C\u6211\u4EEC\u5C31\u4E0D\u5F97\u4E0D\u63D0\u5230\u53E6\u5916\u4E00\u4E2A\u6982\u5FF5\uFF0C\u90A3\u5C31\u662F UML\uFF08Unified Model Language\uFF09\uFF0C\u7EDF\u4E00\u5EFA\u6A21\u8BED\u8A00\u3002\u5F88\u591A\u8BB2\u89E3\u9762\u5411\u5BF9\u8C61\u6216\u8BBE\u8BA1\u6A21\u5F0F\u7684\u4E66\u7C4D\uFF0C\u5E38\u7528\u5B83\u6765\u753B\u56FE\u8868\u8FBE\u9762\u5411\u5BF9\u8C61\u6216\u8BBE\u8BA1\u6A21\u5F0F\u7684\u8BBE\u8BA1\u601D\u8DEF\u3002</p><p>\u5B9E\u9645\u4E0A\uFF0CUML \u662F\u4E00\u79CD\u975E\u5E38\u590D\u6742\u7684\u4E1C\u897F\u3002\u5B83\u4E0D\u4EC5\u4EC5\u5305\u542B\u6211\u4EEC\u5E38\u63D0\u5230\u7C7B\u56FE\uFF0C\u8FD8\u6709\u7528\u4F8B\u56FE\u3001\u987A\u5E8F\u56FE\u3001\u6D3B\u52A8\u56FE\u3001\u72B6\u6001\u56FE\u3001\u7EC4\u4EF6\u56FE\u7B49\u3002\u5728\u6211\u770B\u6765\uFF0C\u5373\u4FBF\u4EC5\u4EC5\u4F7F\u7528\u7C7B\u56FE\uFF0C\u5B66\u4E60\u6210\u672C\u4E5F\u662F\u5F88\u9AD8\u7684\u3002\u5C31\u5355\u8BF4\u7C7B\u4E4B\u95F4\u7684\u5173\u7CFB\uFF0CUML \u5C31\u5B9A\u4E49\u4E86\u5F88\u591A\u79CD\uFF0C\u6BD4\u5982\u6CDB\u5316\u3001\u5B9E\u73B0\u3001\u5173\u8054\u3001\u805A\u5408\u3001\u7EC4\u5408\u3001\u4F9D\u8D56\u7B49\u3002</p><p>\u8981\u60F3\u5B8C\u5168\u638C\u63E1\uFF0C\u5E76\u4E14\u719F\u7EC3\u8FD0\u7528\u8FD9\u4E9B\u7C7B\u4E4B\u95F4\u7684\u5173\u7CFB\uFF0C\u6765\u753B UML \u7C7B\u56FE\uFF0C\u80AF\u5B9A\u8981\u82B1\u5F88\u591A\u7684\u5B66\u4E60\u7CBE\u529B\u3002\u800C\u4E14\uFF0CUML \u4F5C\u4E3A\u4E00\u79CD\u6C9F\u901A\u5DE5\u5177\uFF0C\u5373\u4FBF\u4F60\u80FD\u5B8C\u5168\u6309\u7167 UML \u89C4\u8303\u6765\u753B\u7C7B\u56FE\uFF0C\u53EF\u5BF9\u4E8E\u4E0D\u719F\u6089\u7684\u4EBA\u6765\u8BF4\uFF0C\u770B\u61C2\u7684\u6210\u672C\u4E5F\u8FD8\u662F\u5F88\u9AD8\u7684\u3002</p><p>\u6240\u4EE5\uFF0C\u4ECE\u6211\u7684\u5F00\u53D1\u7ECF\u9A8C\u6765\u8BF4\uFF0CUML \u5728\u4E92\u8054\u7F51\u516C\u53F8\u7684\u9879\u76EE\u5F00\u53D1\u4E2D\uFF0C\u7528\u5904\u53EF\u80FD\u5E76\u4E0D\u5927\u3002\u4E3A\u4E86\u6587\u6863\u5316\u8F6F\u4EF6\u8BBE\u8BA1\u6216\u8005\u65B9\u4FBF\u8BA8\u8BBA\u8F6F\u4EF6\u8BBE\u8BA1\uFF0C\u5927\u90E8\u5206\u60C5\u51B5\u4E0B\uFF0C\u6211\u4EEC\u968F\u624B\u753B\u4E2A\u4E0D\u90A3\u4E48\u89C4\u8303\u7684\u8349\u56FE\uFF0C\u80FD\u591F\u8FBE\u610F\uFF0C\u65B9\u4FBF\u6C9F\u901A\u5C31\u591F\u4E86\uFF0C\u800C\u5B8C\u5168\u6309\u7167 UML \u89C4\u8303\u6765\u5C06\u8349\u56FE\u6807\u51C6\u5316\uFF0C\u6240\u4ED8\u51FA\u7684\u4EE3\u4EF7\u662F\u4E0D\u503C\u5F97\u7684\u3002</p><p>\u6240\u4EE5\uFF0C\u6211\u8FD9\u91CC\u7279\u522B\u8BF4\u660E\u4E00\u4E0B\uFF0C\u4E13\u680F\u4E2D\u7684\u5F88\u591A\u7C7B\u56FE\u6211\u5E76\u6CA1\u6709\u5B8C\u5168\u9075\u5B88 UML \u7684\u89C4\u8303\u6807\u51C6\u3002\u4E3A\u4E86\u517C\u987E\u56FE\u7684\u8868\u8FBE\u80FD\u529B\u548C\u4F60\u7684\u5B66\u4E60\u6210\u672C\uFF0C\u6211\u5BF9 UML \u7C7B\u56FE\u89C4\u8303\u505A\u4E86\u7B80\u5316\uFF0C\u5E76\u914D\u4E0A\u4E86\u8BE6\u7EC6\u7684\u6587\u5B57\u89E3\u91CA\uFF0C\u529B\u56FE\u8BA9\u4F60\u4E00\u773C\u5C31\u80FD\u770B\u61C2\uFF0C\u800C\u975E\u9002\u5F97\u5176\u53CD\uFF0C\u8BA9\u56FE\u52A0\u91CD\u4F60\u7684\u5B66\u4E60\u6210\u672C\u3002\u6BD5\u7ADF\uFF0C\u6211\u4EEC\u7684\u4E13\u680F\u5E76\u4E0D\u662F\u4E00\u4E2A\u8BB2\u65B9\u6CD5\u8BBA\u7684\u6559\u7A0B\uFF0C\u4E13\u680F\u4E2D\u7684\u6240\u6709\u7C7B\u56FE\uFF0C\u672C\u8D28\u662F\u8BA9\u4F60\u66F4\u6E05\u6670\u5730\u7406\u89E3\u8BBE\u8BA1\u3002</p><h2 id="\u91CD\u70B9\u56DE\u987E" tabindex="-1"><a class="header-anchor" href="#\u91CD\u70B9\u56DE\u987E" aria-hidden="true">#</a> \u91CD\u70B9\u56DE\u987E</h2><p><strong>1. \u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\uFF1F</strong></p><p>\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u662F\u4E00\u79CD\u7F16\u7A0B\u8303\u5F0F\u6216\u7F16\u7A0B\u98CE\u683C\u3002\u5B83\u4EE5\u7C7B\u6216\u5BF9\u8C61\u4F5C\u4E3A\u7EC4\u7EC7\u4EE3\u7801\u7684\u57FA\u672C\u5355\u5143\uFF0C\u5E76\u5C06\u5C01\u88C5\u3001\u62BD\u8C61\u3001\u7EE7\u627F\u3001\u591A\u6001\u56DB\u4E2A\u7279\u6027\uFF0C\u4F5C\u4E3A\u4EE3\u7801\u8BBE\u8BA1\u548C\u5B9E\u73B0\u7684\u57FA\u77F3 \u3002</p><p><strong>2. \u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\uFF1F</strong></p><p>\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u662F\u652F\u6301\u7C7B\u6216\u5BF9\u8C61\u7684\u8BED\u6CD5\u673A\u5236\uFF0C\u5E76\u6709\u73B0\u6210\u7684\u8BED\u6CD5\u673A\u5236\uFF0C\u80FD\u65B9\u4FBF\u5730\u5B9E\u73B0\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u56DB\u5927\u7279\u6027\uFF08\u5C01\u88C5\u3001\u62BD\u8C61\u3001\u7EE7\u627F\u3001\u591A\u6001\uFF09\u7684\u7F16\u7A0B\u8BED\u8A00\u3002</p><p><strong>3. \u5982\u4F55\u5224\u5B9A\u4E00\u4E2A\u7F16\u7A0B\u8BED\u8A00\u662F\u5426\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\uFF1F</strong></p><p>\u5982\u679C\u6309\u7167\u4E25\u683C\u7684\u7684\u5B9A\u4E49\uFF0C\u9700\u8981\u6709\u73B0\u6210\u7684\u8BED\u6CD5\u652F\u6301\u7C7B\u3001\u5BF9\u8C61\u3001\u56DB\u5927\u7279\u6027\u624D\u80FD\u53EB\u4F5C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u3002\u5982\u679C\u653E\u5BBD\u8981\u6C42\u7684\u8BDD\uFF0C\u53EA\u8981\u67D0\u79CD\u7F16\u7A0B\u8BED\u8A00\u652F\u6301\u7C7B\u3001\u5BF9\u8C61\u8BED\u6CD5\u673A\u5236\uFF0C\u90A3\u57FA\u672C\u4E0A\u5C31\u53EF\u4EE5\u8BF4\u8FD9\u79CD\u7F16\u7A0B\u8BED\u8A00\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u4E86\uFF0C\u4E0D\u4E00\u5B9A\u975E\u5F97\u8981\u6C42\u5177\u6709\u6240\u6709\u7684\u56DB\u5927\u7279\u6027\u3002</p><p><strong>4. \u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u548C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u4E4B\u95F4\u6709\u4F55\u5173\u7CFB\uFF1F</strong></p><p>\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u4E00\u822C\u4F7F\u7528\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\u6765\u8FDB\u884C\uFF0C\u4F46\u662F\uFF0C\u4E0D\u7528\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\uFF0C\u6211\u4EEC\u7167\u6837\u53EF\u4EE5\u8FDB\u884C\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u3002\u53CD\u8FC7\u6765\u8BB2\uFF0C\u5373\u4FBF\u6211\u4EEC\u4F7F\u7528\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u8BED\u8A00\uFF0C\u5199\u51FA\u6765\u7684\u4EE3\u7801\u4E5F\u4E0D\u4E00\u5B9A\u662F\u9762\u5411\u5BF9\u8C61\u7F16\u7A0B\u98CE\u683C\u7684\uFF0C\u4E5F\u6709\u53EF\u80FD\u662F\u9762\u5411\u8FC7\u7A0B\u7F16\u7A0B\u98CE\u683C\u7684\u3002</p><p><strong>5. \u4EC0\u4E48\u662F\u9762\u5411\u5BF9\u8C61\u5206\u6790\u548C\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\uFF1F</strong></p><p>\u7B80\u5355\u70B9\u8BB2\uFF0C\u9762\u5411\u5BF9\u8C61\u5206\u6790\u5C31\u662F\u8981\u641E\u6E05\u695A\u505A\u4EC0\u4E48\uFF0C\u9762\u5411\u5BF9\u8C61\u8BBE\u8BA1\u5C31\u662F\u8981\u641E\u6E05\u695A\u600E\u4E48\u505A\u3002\u4E24\u4E2A\u9636\u6BB5\u6700\u7EC8\u7684\u4EA7\u51FA\u662F\u7C7B\u7684\u8BBE\u8BA1\uFF0C\u5305\u62EC\u7A0B\u5E8F\u88AB\u62C6\u89E3\u4E3A\u54EA\u4E9B\u7C7B\uFF0C\u6BCF\u4E2A\u7C7B\u6709\u54EA\u4E9B\u5C5E\u6027\u65B9\u6CD5\u3001\u7C7B\u4E0E\u7C7B\u4E4B\u95F4\u5982\u4F55\u4EA4\u4E92\u7B49\u7B49\u3002</p><h2 id="\u8BFE\u5802\u8BA8\u8BBA" tabindex="-1"><a class="header-anchor" href="#\u8BFE\u5802\u8BA8\u8BBA" aria-hidden="true">#</a> \u8BFE\u5802\u8BA8\u8BBA</h2><p>\u4ECA\u5929\u6211\u4EEC\u8981\u8BA8\u8BBA\u7684\u8BDD\u9898\u6709\u4E24\u4E2A\uFF1A</p><p>\u5728\u6587\u7AE0\u4E2D\uFF0C\u6211\u8BB2\u5230 UML \u7684\u5B66\u4E60\u6210\u672C\u5F88\u9AD8\uFF0C\u6C9F\u901A\u6210\u672C\u4E5F\u4E0D\u4F4E\uFF0C\u4E0D\u63A8\u8350\u5728\u9762\u5411\u5BF9\u8C61\u5206\u6790\u3001\u8BBE\u8BA1\u7684\u8FC7\u7A0B\u4E2D\u4F7F\u7528\uFF0C\u5BF9\u6B64\u4F60\u6709\u4F55\u770B\u6CD5\uFF1F</p><blockquote><p>UML\u662F\u63D0\u4F9B\u4E00\u79CD\u89C4\u8303\u548C\u51C6\u5219\uFF0C\u5982\u679C\u4E25\u683C\u7684\u6309\u7167\u89C4\u8303\u6765\u505A\u53EF\u80FD\u8FC7\u72B9\u4E0D\u53CA\uFF0C\u5728\u65F6\u95F4\u6210\u672C\u548C\u89C4\u8303\u4E4B\u95F4\u5FC5\u5C3D\u91CF\u8981\u505A\u5230\u5E73\u8861\u3002</p></blockquote><p>\u6709\u5173\u9762\u5411\u5BF9\u8C61\u7684\u6982\u5FF5\u548C\u77E5\u8BC6\u70B9\uFF0C\u9664\u4E86\u6211\u4EEC\u4ECA\u5929\u8BB2\u5230\u7684\uFF0C\u4F60\u8FD8\u80FD\u60F3\u5230\u5176\u4ED6\u54EA\u4E9B\u5417\uFF1F</p><blockquote><p>\u9664\u4E86\u4EE5\u4E0A\u7684\u6982\u5FF5\uFF0C\u8FD8\u60F3\u5230\u4E86\u4F4E\u8026\u5408\u9AD8\u5185\u805A\uFF0C\u6A21\u5757\u5316\uFF0C\u53EF\u7EF4\u62A4\u6027\uFF0C\u53EF\u6269\u5C55\u6027\uFF0C\u53EF\u590D\u7528\u6027\uFF0C\u5BF9\u8C61\u7684\u552F\u4E00\u6027\uFF0C\u5BF9\u8C61\u7684\u5206\u7C7B\uFF08\u662Fis-a\u8FD8\u662Fhas\u7684\u5173\u7CFB\uFF09\u7B49</p></blockquote>',48);function t(n,i){return r}var o=a(e,[["render",t],["__file","OOP.html.vue"]]);export{o as default};
